2093→/// Cross over two parent mock config vectors, preserving vector structure.
2094→///
2095→/// With probability `crossover_rate`, performs per-value crossover between
2096→/// matching return values. Both children have the same number of configs
2097→/// with the same symbols as the parents.
2098→pub fn crossover_mock_values(
2099→    parent_a: &[MockConfig],
2100→    parent_b: &[MockConfig],
2101→    mock_params: &[MockParam],
2102→    crossover_rate: f64,
2103→    rng: &mut impl Rng,
2104→) -> (Vec<MockConfig>, Vec<MockConfig>) {
2105→    let len = parent_a.len().min(parent_b.len()).min(mock_params.len());
2106→
2107→    if rng.random_range(0.0..1.0_f64) >= crossover_rate {
2108→        return (parent_a.to_vec(), parent_b.to_vec());
2109→    }
2110→
2111→    let mut child1 = Vec::with_capacity(len);
2112→    let mut child2 = Vec::with_capacity(len);
2113→
2114→    for i in 0..len {
2115→        let (rv1, rv2) = crossover_return_values(
2116→            &parent_a[i].return_values,
2117→            &parent_b[i].return_values,
2118→            &mock_params[i].return_type,
2119→            rng,
2120→        );
2121→
2122→        child1.push(MockConfig {
2123→            symbol: parent_a[i].symbol.clone(),
2124→            return_values: rv1,
2125→            should_track_calls: parent_a[i].should_track_calls,
2126→            default_behavior: parent_a[i].default_behavior.clone(),
2127→        });
2128→        child2.push(MockConfig {
2129→            symbol: parent_b[i].symbol.clone(),
2130→            return_values: rv2,
2131→            should_track_calls: parent_b[i].should_track_calls,
2132→            default_behavior: parent_b[i].default_behavior.clone(),
2133→        });
2134→    }
2135→
2136→    (child1, child2)
2137→}
