2139→/// Cross over two return value vectors using per-element type-aware crossover.
2140→fn crossover_return_values(
2141→    a: &[Value],
2142→    b: &[Value],
2143→    typ: &TypeInfo,
2144→    rng: &mut impl Rng,
2145→) -> (Vec<Value>, Vec<Value>) {
2146→    let overlap = a.len().min(b.len());
2147→    let mut rv1 = Vec::with_capacity(a.len());
2148→    let mut rv2 = Vec::with_capacity(b.len());
2149→
2150→    for i in 0..overlap {
2151→        let (c1, c2) = crossover_value(&a[i], &b[i], typ, rng);
2152→        rv1.push(c1);
2153→        rv2.push(c2);
2154→    }
2155→
2156→    rv1.extend(a.iter().skip(overlap).cloned());
2157→    rv2.extend(b.iter().skip(overlap).cloned());
2158→
2159→    (rv1, rv2)
2160→}
